import{M as e}from"./chunks/theme.B4YvUgw1.js";import{I as o,c as l,o as n,aF as t,J as c}from"./chunks/framework.CZ2lsOHd.js";const u=JSON.parse('{"title":"Caching Strategy","description":"Deep dive into the Smart Caching implementation and Namespace Invalidation","frontmatter":{"title":"Caching Strategy","description":"Deep dive into the Smart Caching implementation and Namespace Invalidation"},"headers":[],"relativePath":"architecture/caching-strategy.md","filePath":"architecture/caching-strategy.md","lastUpdated":1777936962000}'),d={name:"architecture/caching-strategy.md"},y=Object.assign(d,{setup(h){const i=[{id:"app",label:"Application Logic",position:{x:50,y:150},style:{background:"#3b82f6",color:"#fff"}},{id:"cache-layer",label:"Cache Action Layer",position:{x:350,y:150},style:{border:"2px solid #3b82f6"}},{id:"redis-sets",label:"Redis (Namespace Sets)",position:{x:650,y:50},style:{background:"#ef4444",color:"#fff"}},{id:"redis-keys",label:"Redis (Data Keys)",position:{x:650,y:250},style:{background:"#ef4444",color:"#fff"}}],r=[{id:"e1",source:"app",target:"cache-layer",label:"1. cache.set(key, val)",animated:!0,markerEnd:e.ArrowClosed},{id:"e2",source:"cache-layer",target:"redis-sets",label:"2. SADD namespace:keys key",type:"smoothstep",markerEnd:e.ArrowClosed},{id:"e3",source:"cache-layer",target:"redis-keys",label:"3. SET key val",type:"smoothstep",markerEnd:e.ArrowClosed},{id:"e4",source:"app",target:"cache-layer",label:"4. cache.del(namespace/*)",position:{x:200,y:300},style:{stroke:"#ef4444"},markerEnd:e.ArrowClosed},{id:"e5",source:"cache-layer",target:"redis-sets",label:"5. SMEMBERS -> DEL keys",sourceHandle:"right",targetHandle:"left",style:{stroke:"#ef4444"},markerEnd:e.ArrowClosed}];return(p,a)=>{const s=o("InteractiveFlow");return n(),l("div",null,[a[0]||(a[0]=t('<h1 id="caching-strategy" tabindex="-1">Caching Strategy <a class="header-anchor" href="#caching-strategy" aria-label="Permalink to “Caching Strategy”">​</a></h1><p>The TypeScript Boilerplate features a sophisticated <strong>Smart Caching</strong> system built on top of Redis. It prioritizes performance, high availability, and data consistency through advanced invalidation patterns.</p><h2 id="architectural-overview" tabindex="-1">Architectural Overview <a class="header-anchor" href="#architectural-overview" aria-label="Permalink to “Architectural Overview”">​</a></h2><p>The system uses a <strong>Cache-aside (Lazy Loading)</strong> pattern combined with a custom <strong>Namespace Management</strong> layer using Redis Sets.</p>',4)),c(s,{nodes:i,edges:r}),a[1]||(a[1]=t('<h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to “Key Features”">​</a></h2><h3 id="hierarchical-invalidation" tabindex="-1">Hierarchical Invalidation <a class="header-anchor" href="#hierarchical-invalidation" aria-label="Permalink to “Hierarchical Invalidation”">​</a></h3><p>The system now supports <strong>Hierarchical Invalidation</strong>. When a key is stored, it is automatically indexed in all its parent namespaces.</p><ul><li>Key: <code>api/v1/users/profile/{id:123}</code></li><li>Parent Namespaces: <code>api</code>, <code>api/v1</code>, <code>api/v1/users</code>, <code>api/v1/users/profile</code>.</li></ul><p>This allows for broad invalidations like <code>del(&#39;api/v1/*&#39;)</code> to correctly purge all nested keys across different sub-paths.</p><h3 id="_2-graceful-degradation" tabindex="-1">2. Graceful Degradation <a class="header-anchor" href="#_2-graceful-degradation" aria-label="Permalink to “2. Graceful Degradation”">​</a></h3><p>The system is built to be resilient. If the Redis server goes down:</p><ul><li>The API will <strong>not</strong> throw errors.</li><li><code>cache.get()</code> will return <code>null</code>, falling back to the database.</li><li><code>cache.set()</code> and <code>cache.del()</code> calls will resolve silently.</li><li>Performance will decrease (higher DB load), but <strong>availability is preserved</strong>.</li></ul><h3 id="_3-redis-stack-support" tabindex="-1">3. Redis Stack Support <a class="header-anchor" href="#_3-redis-stack-support" aria-label="Permalink to “3. Redis Stack Support”">​</a></h3><p>The boilerplate automatically detects if <strong>Redis Stack</strong> is available (via <code>REDIS_STACK=true</code>).</p><ul><li>If enabled, it uses <code>JSON.SET</code> and <code>JSON.GET</code> for native JSON support.</li><li>If disabled, it transparently falls back to <code>SET</code> with stringification.</li></ul><h2 id="implementation-details" tabindex="-1">Implementation Details <a class="header-anchor" href="#implementation-details" aria-label="Permalink to “Implementation Details”">​</a></h2><h3 id="namespace-auto-detection" tabindex="-1">Namespace Auto-Detection <a class="header-anchor" href="#namespace-auto-detection" aria-label="Permalink to “Namespace Auto-Detection”">​</a></h3><p>The namespace is automatically extracted from the key. If the key contains curly braces (e.g., <code>user{123}</code>), the part before <code>{</code> is used as the namespace. Otherwise, the key itself acts as the primary namespace reference.</p><h3 id="stale-key-management" tabindex="-1">Stale Key Management <a class="header-anchor" href="#stale-key-management" aria-label="Permalink to “Stale Key Management”">​</a></h3><p>When a key expires via <strong>TTL</strong>, it remains in the Redis Set until the next pattern-based deletion. This is a deliberate design choice to minimize write-heavy set cleanups. The <code>get</code> implementation manually verifies key existence to ensure no stale data is returned.</p><hr><p><strong>See Also:</strong></p><ul><li><a href="/TypeScript-Boilerplate/reference/cache-actions-reference.html">Cache Actions Reference</a> - API documentation</li><li><a href="/TypeScript-Boilerplate/guide/getting-started.html">Getting Started</a> - How to configure Redis</li></ul>',19))])}}});export{u as __pageData,y as default};
